#!/usr/bin/env python3
import csv

# Read input.csv and process data
data = []
with open("input.csv", mode="r") as file:
    reader = csv.DictReader(file)
    for row in reader:
        if row["status"] == "active":
            data.append(row)

# Group by department and compute statistics
department_stats = {}
for row in data:
    dept = row["department"]
    salary = float(row["salary"])
    if dept not in department_stats:
        department_stats[dept] = {"total_salary": 0.0, "count": 0}
    department_stats[dept]["total_salary"] += salary
    department_stats[dept]["count"] += 1

# Prepare output data
output_data = []
for dept, stats in sorted(department_stats.items()):
    avg_salary = round(stats["total_salary"] / stats["count"], 2)
    output_data.append(
        {"department": dept, "avg_salary": avg_salary, "count": stats["count"]}
    )

# Write to output.csv
with open("output.csv", mode="w", newline="") as file:
    fieldnames = ["department", "avg_salary", "count"]
    writer = csv.DictWriter(file, fieldnames=fieldnames)
    writer.writeheader()
    writer.writerows(output_data)
